/**
 * @summary List tasks for a project
 */
export const getListProjectTasksUrl = (
  projectId: number,
  params?: ListProjectTasksParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/projects/${projectId}/tasks?${stringifiedParams}`
    : `/api/projects/${projectId}/tasks`;
};

export const listProjectTasks = async (
  projectId: number,
  params?: ListProjectTasksParams,
  options?: RequestInit,
): Promise<Task[]> => {
  return customFetch<Task[]>(getListProjectTasksUrl(projectId, params), {
    ...options,
    method: "GET",
  });
};

export const getListProjectTasksQueryKey = (
  projectId: number,
  params?: ListProjectTasksParams,
) => {
  return [
    `/api/projects/${projectId}/tasks`,
    ...(params ? [params] : []),
  ] as const;
};

export const getListProjectTasksQueryOptions = <
  TData = Awaited<ReturnType<typeof listProjectTasks>>,
  TError = ErrorType<unknown>,
>(
  projectId: number,
  params?: ListProjectTasksParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof listProjectTasks>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey =
    queryOptions?.queryKey ?? getListProjectTasksQueryKey(projectId, params);

  const queryFn: QueryFunction<
    Awaited<ReturnType<typeof listProjectTasks>>
  > = ({ signal }) =>
    listProjectTasks(projectId, params, { signal, ...requestOptions });

  return {
    queryKey,
    queryFn,
    enabled: !!projectId,
    ...queryOptions,
  } as UseQueryOptions<
    Awaited<ReturnType<typeof listProjectTasks>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

